class TestSessionEntryAgentLifecycle:
    """Test agent dict operations that the controller relies on."""

    def test_register_agent(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        assert len(entry.agents) == 1
        assert entry.agents["a1"].state == StatusState.WORKING

    def test_update_agent_state(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.agents["a1"].state = StatusState.PERMISSION_REQUIRED
        assert entry.agents["a1"].state == StatusState.PERMISSION_REQUIRED
        assert entry.effective_state == StatusState.PERMISSION_REQUIRED

    def test_remove_agent(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        removed = entry.agents.pop("a1", None)
        assert removed is not None
        assert len(entry.agents) == 0

    def test_remove_nonexistent_agent(self):
        entry = _SessionEntry(_make_session())
        removed = entry.agents.pop("nonexistent", None)
        assert removed is None

    def test_clear_all_agents(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.agents["a2"] = _AgentEntry(agent_id="a2", state=StatusState.IDLE)
        entry.agents.clear()
        assert len(entry.agents) == 0
        assert entry.effective_state == entry.state

    def test_agent_count_after_multiple_ops(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.agents["a2"] = _AgentEntry(agent_id="a2", state=StatusState.IDLE)
        entry.agents["a3"] = _AgentEntry(agent_id="a3", state=StatusState.WORKING)
        assert len(entry.agents) == 3
        entry.agents.pop("a2")
        assert len(entry.agents) == 2


class TestStatePriority:
    """Test module-level _STATE_PRIORITY constant."""

    def test_all_states_have_priority(self):
        for state in StatusState:
            assert state in _STATE_PRIORITY, f"{state} missing from _STATE_PRIORITY"

    def test_permission_required_is_highest(self):
        assert _STATE_PRIORITY[StatusState.PERMISSION_REQUIRED] == 0

    def test_idle_is_lowest(self):
        highest_val = max(_STATE_PRIORITY.values())
        assert _STATE_PRIORITY[StatusState.IDLE] == highest_val
